external_knowledge:
- "beacon" metaphorically refers to the event that stands out, drawing many participants;
- "heart of Texas" refers to the state of Texas where the event is taking place;
- "gathering the most runners" refers to the highest number of participants in a running event;
- "physical ground" refers to the event not being virtual;
- "Lone Star state" is a nickname for Texas.

sql:
SELECT locations.location_name, locations.city
FROM events
INNER JOIN locations ON events.location_id = locations.location_id;

SELECT COUNT(DISTINCT type_id)
FROM events
WHERE strftime('%Y', event_date) >= strftime('%Y', 'now') - 1;

SELECT events.event_id, events.event_name, event_types.type_name
FROM events
JOIN event_types ON events.type_id = event_types.type_id;

SELECT e.event_name, l.location_name
FROM events e
INNER JOIN locations l ON e.location_id = l.location_id;
